// Should be used with caution, it only matches routes generated by Twirp Go clients,
// with the default "/twirp" prefix and default CamelCase service and method names.
// More info: https://twitchtv.github.io/twirp/docs/routing.html
const MCPServerServicePathPrefix = "/twirp/agents.v1.MCPServerService/"

func (s *mCPServerServiceServer) ServeHTTP(resp http.ResponseWriter, req *http.Request) {
	ctx := req.Context()
	ctx = ctxsetters.WithPackageName(ctx, "agents.v1")
	ctx = ctxsetters.WithServiceName(ctx, "MCPServerService")
	ctx = ctxsetters.WithResponseWriter(ctx, resp)

	var err error
	ctx, err = callRequestReceived(ctx, s.hooks)
	if err != nil {
		s.writeError(ctx, resp, err)
		return
	}

	if req.Method != "POST" {
		msg := fmt.Sprintf("unsupported method %q (only POST is allowed)", req.Method)
		s.writeError(ctx, resp, badRouteError(msg, req.Method, req.URL.Path))
		return
	}

	// Verify path format: [<prefix>]/<package>.<Service>/<Method>
	prefix, pkgService, method := parseTwirpPath(req.URL.Path)
	if pkgService != "agents.v1.MCPServerService" {
		msg := fmt.Sprintf("no handler for path %q", req.URL.Path)
		s.writeError(ctx, resp, badRouteError(msg, req.Method, req.URL.Path))
		return
	}
	if prefix != s.pathPrefix {
		msg := fmt.Sprintf("invalid path prefix %q, expected %q, on path %q", prefix, s.pathPrefix, req.URL.Path)
		s.writeError(ctx, resp, badRouteError(msg, req.Method, req.URL.Path))
		return
	}

	switch method {
	case "ListMCPServers":
		s.serveListMCPServers(ctx, resp, req)
		return
	case "GetMCPServer":
		s.serveGetMCPServer(ctx, resp, req)
		return
	case "CreateMCPServer":
		s.serveCreateMCPServer(ctx, resp, req)
		return
	case "UpdateMCPServer":
		s.serveUpdateMCPServer(ctx, resp, req)
		return
	case "DeleteMCPServer":
		s.serveDeleteMCPServer(ctx, resp, req)
		return
	case "GetMCPServerStatus":
		s.serveGetMCPServerStatus(ctx, resp, req)
		return
	default:
		msg := fmt.Sprintf("no handler for path %q", req.URL.Path)
		s.writeError(ctx, resp, badRouteError(msg, req.Method, req.URL.Path))
		return
	}
}

